  1→import { implement, ORPCError } from "@orpc/server";
  2→import { contract } from "@rudel/api-routes";
  3→import { member } from "@rudel/sql-schema";
  4→import { and, eq } from "drizzle-orm";
  5→import type { Session } from "./auth.js";
  6→import { db } from "./db.js";
  7→
  8→export interface AppContext {
  9→	user: Session["user"] | null;
 10→	session: Session["session"] | null;
 11→	apiKeyId: string | null;
 12→}
 13→
 14→export const os = implement(contract).$context<AppContext>();
 15→
 16→export const authMiddleware = os.middleware(async ({ context, next }) => {
 17→	if (!context.user || !context.session) {
 18→		throw new ORPCError("UNAUTHORIZED");
 19→	}
 20→	return next({
 21→		context: {
 22→			user: context.user,
 23→			session: context.session,
 24→			apiKeyId: context.apiKeyId,
 25→		},
 26→	});
 27→});
 28→
 29→export const orgMiddleware = os.middleware(async ({ context, next }) => {
 30→	if (!context.user || !context.session) {
 31→		throw new ORPCError("UNAUTHORIZED");
 32→	}
 33→	const organizationId =
 34→		(context.session as Record<string, unknown>).activeOrganizationId ??
 35→		context.user.id;
 36→	if (!organizationId || typeof organizationId !== "string") {
 37→		throw new ORPCError("BAD_REQUEST", {
 38→			message: "No active organization",
 39→		});
 40→	}
 41→
 42→	// Personal workspace: user is implicitly the owner
 43→	let userRole: "owner" | "admin" | "member" = "owner";
 44→
 45→	// When the active org is not the user's personal workspace, verify membership
 46→	if (organizationId !== context.user.id) {
 47→		const membership = await db
 48→			.select({ id: member.id, role: member.role })
 49→			.from(member)
 50→			.where(
 51→				and(
 52→					eq(member.organizationId, organizationId),
 53→					eq(member.userId, context.user.id),
 54→				),
 55→			)
 56→			.limit(1);
 57→
 58→		if (membership.length === 0) {
 59→			throw new ORPCError("FORBIDDEN", {
 60→				message: "Not a member of the active organization",
 61→			});
 62→		}
 63→		const row = membership[0];
 64→		if (row) {
 65→			userRole = (row.role as "owner" | "admin" | "member") ?? "member";
 66→		}
 67→	}
 68→
 69→	const isOrgAdmin = userRole === "owner" || userRole === "admin";
 70→
 71→	return next({
 72→		context: {
 73→			user: context.user,
 74→			session: context.session,
 75→			apiKeyId: context.apiKeyId,
 76→			organizationId,
 77→			userRole,
 78→			isOrgAdmin,
 79→		},
 80→	});
 81→});
 82→
 83→export const ingestAuthMiddleware = os.middleware(async ({ context, next }) => {
 84→	if (!context.user) {
 85→		throw new ORPCError("UNAUTHORIZED");
 86→	}
 87→
 88→	if (!context.session && !context.apiKeyId) {
 89→		throw new ORPCError("UNAUTHORIZED");
 90→	}
 91→
 92→	return next({
 93→		context: {
 94→			user: context.user,
 95→			session: context.session,
 96→			apiKeyId: context.apiKeyId,
 97→		},
 98→	});
 99→});
